/**
 * CinematicDirection — the AI-generated visual direction for a lyric video.
 *
 * Generated by: supabase/functions/cinematic-direction
 * Consumed by: fontResolver, sceneCompiler, LyricDancePlayer, generate-section-images
 */

export interface VideoOptions {
  /** Canvas-drawn beat visualizer strip (reactive to beat energy). */
  beatVisualizer: boolean;
  /** Canvas-drawn dynamite wick progress bar. */
  wickBar: boolean;
  /** Preset for flash strength, scrim darkness, and vignette intensity. */
  intensity: 'soft' | 'hard';
}

export const DEFAULT_VIDEO_OPTIONS: VideoOptions = {
  beatVisualizer: false,
  wickBar: false,
  intensity: 'soft',
};

export interface CinematicDirection {
  /** One-sentence world description */
  description?: string;
  /** Typography plan — font, weight, hero style, per-section behaviors */
  typographyPlan?: {
    system: string;
    primary: string;
    case: string;
    baseWeight: string;
    heroStyle: string;
    accentDensity: string;
    sectionBehavior?: Record<string, string>;
  };
  /** Per-section visual direction */
  sections?: CinematicSection[];

  /** Client-built phrase groupings */
  phrases?: CinematicPhrase[];
  /** Client-detected hook phrase text */
  hookPhrase?: string;
  /** Client-detected signature/thesis phrase text */
  signaturePhrase?: string;

  /** Beat grid summary attached by client */
  beat_grid?: { bpm: number; confidence: number };
  /** Creator-controlled rendering options. Defaults applied when absent. */
  options?: VideoOptions;
}

export interface CinematicSection {
  sectionIndex: number;
  /** One evocative sentence — what the viewer sees */
  description: string;
  /** Visual mood — drives camera, color grading, image style */
  visualMood?: string;
  /** Hex color — primary emotional color, proposed by model */
  dominantColor?: string;
  /** Particle system type */
  texture?: string;
  /** Time boundaries */
  startSec?: number;
  endSec?: number;
  /** Computed ratios (from enrichSections) */
  startRatio?: number;
  endRatio?: number;
  /** Audio energy level */
  avgEnergy?: number;
  /** Peak energy in section */
  peakEnergy?: number;
  /** Section role (intro/main/outro) */
  role?: string;
  /** AI-suggested hero words for this section */
  heroWords?: string[];
}

export interface CinematicPhrase {
  /** Inclusive range of global word indices: [start, end] */
  wordRange: [number, number];
  /** Most impactful word — UPPERCASE */
  heroWord?: string;
  /** Multiple hero words from section-level AI suggestion */
  heroWords?: string[];
  /**
   * @deprecated Reveal style is now variety-derived from phrase duration + word count.
   * This field is accepted for backward-compat with cached AI outputs but is ignored
   * by the compiler. New AI prompts should not request this field.
   */
  revealStyle?: 'instant' | 'stagger_fast' | 'stagger_slow';
  /**
   * @deprecated Composition is now variety-assigned (line vs stack rotation).
   * The AI can still influence composition via `isCenterWord`.
   * This field is accepted for backward-compat and ignored by the compiler.
   */
  composition?: 'stack' | 'line' | 'center_word';
  /**
   * AI signal: true when a single dominant word should use center_word treatment.
   */
  isCenterWord?: boolean;
  /**
   * @deprecated Bias is now variety-assigned (left/center/right rotation).
   * This field is accepted for backward-compat and ignored by the compiler.
   */
  bias?: 'left' | 'center' | 'right';
  /**
   * AI signal: this phrase is a climax/emphasis moment and should use a dramatic exit.
   */
  isClimax?: boolean;
  /**
   * AI signal: specific dramatic exit for climax phrases.
   * Kept as full union for backward-compat parsing of cached AI outputs.
   */
  exitEffect?: 'fade' | 'drift_up' | 'shrink' | 'dissolve' | 'cascade' | 'scatter' | 'slam' | 'glitch' | 'burn';
  /** Hold timing class */
  holdClass?: 'short_hit' | 'medium_groove' | 'long_emotional';
  /** Phrase text */
  text?: string;
  /** Word count */
  wordCount?: number;
  /** Timing */
  start?: number;
  end?: number;
  durationMs?: number;
}
